import java.util.List;

public class Solution {
    public static String solveBruteForce(int m, List<String> s) {
        double totalSum = 0;

        for (String str : s) {
            double currentProduct = 1;
            for (int j = 0; j < str.length(); j++) {
                int asciiVal = (int) str.charAt(j);
                // Directly computing the exponent (Will overflow/turn into Infinity)
                currentProduct *= Math.pow(asciiVal, m); 
            }
            totalSum += currentProduct;
        }

        // Checking parity of the overflowed sum
        if (totalSum % 2 != 0) {
            return "ODD";
        } else {
            return "EVEN";
        }
    }
}
