import java.util.*;

class Result {
    /*
     * Complete the 'solve' function below.
     *
     * The function is expected to return a STRING.
     * The function accepts following parameters:
     * 1. INTEGER m
     * 2. STRING_ARRAY s
     */
    public static String solve(int m, List<String> s) {
        int oddStringCount = 0;

        // Iterate through each string in the list
        for (String str : s) {
            boolean allCharactersAreOdd = true;

            // Check the parity of each character's ASCII value
            for (int j = 0; j < str.length(); j++) {
                int asciiValue = (int) str.charAt(j);

                // If any character is even, the whole string product becomes even
                if (asciiValue % 2 == 0) {
                    allCharactersAreOdd = false;
                    break; // No need to check the rest of this string
                }
            }

            // If the string contains ONLY odd characters, its value is odd
            if (allCharactersAreOdd) {
                oddStringCount++;
            }
        }

        // If we have an odd count of odd-valued strings, the total sum is ODD
        if (oddStringCount % 2 != 0) {
            return "ODD";
        } else {
            return "EVEN";
        }
    }
}
